_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // GROW EFFECT - bright pixels spread radially outward.
    // BE CAREFUL - this can really thrash the texture cache! (SLOW)
    float grad_rad = 3;  //TWEAK
    float str = 2.3;      //TWEAK
    vec3 d = vec3(uTexSize.zw, 0) * grad_rad;
    vec4 lums = 0;
    lums.x = lum( MyGet(vUv + uTexSize.zw*d.xz) );
    lums.y = lum( MyGet(vUv - uTexSize.zw*d.xz) );
    lums.z = lum( MyGet(vUv + uTexSize.zw*d.zy) );
    lums.w = lum( MyGet(vUv - uTexSize.zw*d.zy) );
    vec2 grad = vec2(lums.x-lums.y, lums.z-lums.w)*str*1000/grad_rad;
    grad = (clamp01(grad*0.5+0.5)*2-1)*1.4;
    // sample previous uFrame
    ret = texture( sampler_fc_main, vUv + grad*uTexSize.zw ).xyz;

    // darken (decay) over uTime
    ret *= 0.95; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2=vUv;
uv2.x=1-uv2.x;
vec2 uv3=vUv;
uv3.y=1-uv3.y;

    vec2 d = uTexSize.zw*4;
    float1 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) ).y;
    float1 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) ).y;
    vec2 uv_y = vUv-vec2(dx,dy)*0.4;

    vec2 d2 = uTexSize.zw*4;
    float1 dx2 = ( GetBlur1(uv2+vec2(1,0)*d2)-GetBlur1(uv2-vec2(1,0)*d2) ).y;
    float1 dy2 = ( GetBlur1(uv2+vec2(0,1)*d2)-GetBlur1(uv2-vec2(0,1)*d2) ).y;
    vec2 uv2_y = uv2-vec2(dx2,dy)*0.36;

    vec2 d3 = uTexSize.zw*4;
    float1 dx3 = ( GetBlur1(uv3+vec2(1,0)*d3)-GetBlur1(uv3-vec2(1,0)*d3) ).y;
    float1 dy3 = ( GetBlur1(uv3+vec2(2,1)*d3)-GetBlur1(uv3-vec2(0,1)*d3) ).y;
    vec2 uv3_y = uv3-vec2(dx3,dy3)*1.36;

ret = mix(vec3(2,1.1,1.8)*texture(sampler_fc_main, uv_y).x,
           mix(vec3(1.8,0.4,2.5),vec3(2.8,2.4,0),GetPixel(vUv).z),
           GetBlur1(vUv).y*0.5);
ret = mix( ret, vec3(1.4,1,2.3), GetPixel(uv_y).z);

vec3 ret2= mix(vec3(2,0.5,2.7)*texture(sampler_fc_main, uv2_y).x,
           mix(vec3(0,2.5,1),vec3(2.9,0.3,2.8),GetPixel(uv2).z),
           GetBlur1(uv2).y*1.5);
ret2= mix( ret2, vec3(0.2,2.2,2.8), GetPixel(uv_y).z);

vec3 ret3= mix(vec3(2.9,0.9,0.5)*texture(sampler_fc_main, uv3_y).x,
           mix(vec3(2.1,0.9,2.5),vec3(1.9,0.5,1.9),GetPixel(uv3).z),
           GetBlur1(uv3).y*1.54);
ret3= mix( ret3, vec3(1.7,0.5,1.6), GetPixel(uv3_y).z);

ret+=ret-ret3;

  fragColor = ret;
}
